import requests


class Tools:
    @staticmethod
    def run(
        query: str, result_type: str = "core", page: int = 1, page_size: int = 10
    ) -> dict:
        """
        Search Europe PMC for OA papers, preprints, grants.
        result_type: "core" (default), "book", "patent", "grant"
        Returns title, abstract, DOI, PMC ID, full-text links.
        """
        base_url = "https://www.ebi.ac.uk/europepmc/webservices/rest/search"

        params = {
            "query": query,
            "resultType": result_type,
            "page": page,
            "pageSize": page_size,
            "format": "json",
        }

        try:
            r = requests.get(base_url, params=params, timeout=15)
            r.raise_for_status()
            data = r.json()

            # Enrich with direct PMC links when available
            if "resultList" in data and "result" in data["resultList"]:
                for item in data["resultList"]["result"]:
                    if "pmcid" in item:
                        item["full_text_url"] = (
                            f"https://europepmc.org/article/PMC/{item['pmcid'].replace('PMC', '')}"
                        )
                    if "doi" in item:
                        item["doi_url"] = f"https://doi.org/{item['doi']}"

            return data
        except Exception as e:
            return {"error": str(e)}

