class Tools:
    @staticmethod
    def run(
        query: str,
        service: str = "dimensions",
        entity_type: str = "publications",
        limit: int = 10,
    ) -> dict:
        """
        Search Dimensions.ai or Lens.org for papers, grants, patents, citations, funding.
        service: "dimensions" or "lens"
        entity_type: "publications", "grants", "patents", "researchers"
        """
        service = service.lower()
        api_key = None
        base_url = None

        if service == "dimensions":
            # Dimensions requires paid API key in most cases
            api_key = os.environ.get(
                "DIMENSIONS_API_KEY"
            )  # ← add to .env if you have one
            base_url = "https://api.dimensions.ai/v1"
            if not api_key:
                return {
                    "error": "DIMENSIONS_API_KEY not found — add to .env or use public search link"
                }

            # Example: public search fallback
            return {
                "search_url": f"https://app.dimensions.ai/discover/publication?search_text={requests.compat.quote(query)}",
                "note": "Visit link for results. Full API needs paid key.",
            }

        elif service == "lens":
            # Lens.org has public API (rate-limited)
            base_url = "https://api.lens.org/scholarly/search"
            headers = {
                "Authorization": (
                    f"Bearer {os.environ.get('LENS_API_KEY')}"
                    if os.environ.get("LENS_API_KEY")
                    else None
                )
            }
            payload = {"query": {"match": {"title": query}}, "size": limit}

            try:
                r = requests.post(
                    base_url, headers=headers or {}, json=payload, timeout=15
                )
                if r.status_code == 200:
                    return r.json()
                else:
                    return {
                        "search_url": f"https://www.lens.org/lens/search/scholar/list?q={requests.compat.quote(query)}",
                        "note": "Visit link for results. Full API needs key.",
                    }
            except Exception as e:
                return {"error": str(e)}

        return {"error": "Unknown service"}

