class Tools:
    @staticmethod
    def run(endpoint: str, params: dict = None) -> dict:
        """
        Calls Semantic Scholar Graph API v1.
        endpoint: e.g. "paper/search", "paper/{paperId}", "paper/{paperId}/citations"
        params: dict of query params (optional)
        Automatically adds useful fields like abstract, url, venue if not specified.
        """
        api_key = os.environ.get("SEMANTIC_SCHOLAR_API_KEY")
        if not api_key:
            return {"error": "SEMANTIC_SCHOLAR_API_KEY not found"}

        base_url = "https://api.semanticscholar.org/graph/v1"
        url = f"{base_url}/{endpoint.lstrip('/')}"

        headers = {"x-api-key": api_key, "Accept": "application/json"}

        if params is None:
            params = {}

        # Auto-add useful fields if not already present (for /paper/search)
        if "paper/search" in endpoint and "fields" in params:
            current_fields = params["fields"].split(",")
            needed = ["abstract", "url", "venue"]
            for f in needed:
                if f not in current_fields:
                    current_fields.append(f)
            params["fields"] = ",".join(current_fields)

        try:
            response = requests.get(url, headers=headers, params=params, timeout=12)
            response.raise_for_status()
            data = response.json()

            # For /paper/search results, enrich each paper with full URL if missing
            if "data" in data:
                for paper in data["data"]:
                    if "paperId" in paper and "url" not in paper:
                        paper["url"] = (
                            f"https://www.semanticscholar.org/paper/{paper['paperId']}"
                        )

            return data
        except requests.exceptions.HTTPError as e:
            return {
                "error": f"HTTP {response.status_code}: {response.text[:300]}",
                "status_code": response.status_code,
            }
        except Exception as e:
            return {"error": str(e)}

